(9, 'John Wick', 101, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/C0BMx-qxsP4?si=FNuMDrqfPc88b003', 'En före detta lönnmördare kommer ur pension för att jaga männen som stal hans bil och dödade hans hund.', 'john_wick.jpg', '{"actor": "Keanu Reeves, Michael Nyqvist", "director": "Chad Stahelski", "release_year": "2014", "production_company": "Summit Entertainment", "production_counrty": "USA"}', 'action', '15+', 2),
(10, 'Mad Max: Fury Road', 120, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/hEJnMQG9ev8?si=nEaSorRMU8rd3ugK', 'I en postapokalyptisk värld revolterar en kvinna mot en tyrannisk härskare.', 'mad_max.jpg', '{"actor": "Tom Hardy, Charlize Theron", "director": "George Miller", "release_year": "2015", "production_company": "Warner Bros.", "production_counrty": "Australia"}', 'action', '15+', 2),
(11, 'The Dark Knight', 152, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/TQfATDZY5Y4?si=_2yCmCrhdZQuZGIf', 'Batman kämpar mot kaos när Jokern sprider skräck i Gotham City.', 'dark_knight.jpg', '{"actor": "Christian Bale, Heath Ledger", "director": "Christopher Nolan", "release_year": "2008", "production_company": "Legendary Pictures", "production_counrty": "USA"}', 'action', '11+', 2),
(12, 'Die Hard', 132, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/gYWvwkXreaI?si=fOcDA-8IGZd2Bxm7', 'En polis i New York försöker rädda sin fru och andra som tagits som gisslan under en julfest.', 'die_hard.jpg', '{"actor": "Bruce Willis, Alan Rickman", "director": "John McTiernan", "release_year": "1988", "production_company": "20th Century Fox", "production_counrty": "USA"}', 'action', '15+', 2),
(13, 'Schindlers List', 195, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/mxphAlJID9U?si=q_t5AiNnUhfMR8YF', 'Berättelsen om hur industrimannen Oskar Schindler räddade över tusen judar under förintelsen.', 'schindlers_list.jpg', '{"actor": "Liam Neeson, Ben Kingsley", "director": "Steven Spielberg", "release_year": "1993", "production_company": "Universal Pictures", "production_counrty": "USA"}', 'blackandwhite', '15+', 2),
(14, 'Psycho', 109, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/Wz719b9QUqY?si=osIvhr8_hT3wfVby', 'En sekreterare på flykt checkar in på ett avlägset motell som drivs av en märklig man.', 'psycho.jpg', '{"actor": "Anthony Perkins, Janet Leigh", "director": "Alfred Hitchcock", "release_year": "1960", "production_company": "Paramount Pictures", "production_counrty": "USA"}', 'blackandwhite', '15+', 2),
(15, 'Casablanca', 102, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/MF7JH_54d8c?si=p-gGCanYsw72Np7d', 'I Marocko under andra världskriget måste en cynisk caféägare välja mellan kärlek och dygd.', 'casablanca.jpg', '{"actor": "Humphrey Bogart, Ingrid Bergman", "director": "Michael Curtiz", "release_year": "1942", "production_company": "Warner Bros.", "production_counrty": "USA"}', 'blackandwhite', 'btl', 2),
(16, 'Raging Bull', 129, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/F2UKuKxCJqc?si=NcPsw2xuXeXEB4bN', 'Historien om boxaren Jake LaMotta vars våldsamma temperament ledde honom till framgång men förstörde hans privatliv.', 'raging_bull.jpg', '{"actor": "Robert De Niro, Joe Pesci", "director": "Martin Scorsese", "release_year": "1980", "production_company": "Chartoff-Winkler", "production_counrty": "USA"}', 'blackandwhite', '15+', 2),
(17, 'The Godfather', 175, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/UaVTIH8mujA?si=Uq8hHV7aFMyjP6RH', 'Den åldrande patriarken i en organiserad brottsdynasti överför kontrollen till sin motvilliga son.', 'godfather.jpg', '{"actor": "Marlon Brando, Al Pacino", "director": "Francis Ford Coppola", "release_year": "1972", "production_company": "Paramount Pictures", "production_counrty": "USA"}', 'classic', '15+', 2),
(18, 'Pulp Fiction', 154, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/s7EdQ4FqbhY?si=6vUCtk7y-6zYBkwG', 'Livet för två lönnmördare, en boxare och ett par rånare flätas samman i Los Angeles.', 'pulp_fiction.jpg', '{"actor": "John Travolta, Uma Thurman", "director": "Quentin Tarantino", "release_year": "1994", "production_company": "Miramax", "production_counrty": "USA"}', 'classic', '15+', 2),
(19, 'Forrest Gump', 142, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/bLvqoHBptjg?si=RLlGeSrs9TMAldvo', 'En man med lågt IQ bevittnar och påverkar oavsiktligt flera historiska händelser i USA.', 'forrest_gump.jpg', '{"actor": "Tom Hanks, Robin Wright", "director": "Robert Zemeckis", "release_year": "1994", "production_company": "Paramount Pictures", "production_counrty": "USA"}', 'classic', '7+', 2),
(20, 'Cinema Paradiso', 155, 'Italienska', 'Svenska', 'https://www.youtube.com/embed/JMyVSD6OvO8?si=uNhR4K4CCnTk3bY2', 'En hyllning till filmen genom vänskapen mellan en pojke och en gammal maskinist.', 'cinema_paradiso.jpg', '{"actor": "Philippe Noiret, Salvatore Cascio", "director": "Giuseppe Tornatore", "release_year": "1988", "production_company": "Les Films Ariane", "production_counrty": "Italy"}', 'classic', 'btl', 2),
(21, 'The Big Lebowski', 117, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/cd-go0oBF4Y?si=x9H840xKN9i8bdLH', 'En arbetslös slackare i LA blir förväxlad med en miljonär med samma namn.', 'big_lebowski.jpg', '{"actor": "Jeff Bridges, John Goodman", "director": "Joel Coen", "release_year": "1998", "production_company": "Working Title Films", "production_counrty": "USA"}', 'comedy', '15+', 2),
(22, 'Superbad', 113, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/4eaZ_48ZYog?si=ViTGov0SxsGqmg1g', 'Två tonårskillar planerar en episk festkväll för att imponera på tjejer innan de tar studenten.', 'superbad.jpg', '{"actor": "Jonah Hill, Michael Cera", "director": "Greg Mottola", "release_year": "2007", "production_company": "Columbia Pictures", "production_counrty": "USA"}', 'comedy', '15+', 2),
(23, 'The Hangover', 100, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/tlize92ffnY?si=vlKHGi5vdzYqhn7U', 'Tre vänner vaknar upp i Las Vegas efter en svensexa utan minne av vad som hänt och med brudgummen försvunnen.', 'hangover.jpg', '{"actor": "Bradley Cooper, Zach Galifianakis", "director": "Todd Phillips", "release_year": "2009", "production_company": "Legendary Pictures", "production_counrty": "USA"}', 'comedy', '11+', 2),
(24, 'Monty Python and the Holy Grail', 91, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/urRkGvhXc8w?si=inj_gVu40Td5yZBQ', 'Kung Arthur och hans riddare ger sig ut på ett minst sagt absurt sökande efter den heliga graalen.', 'holy_grail.jpg', '{"actor": "John Cleese, Eric Idle", "director": "Terry Gilliam", "release_year": "1975", "production_company": "Python Pictures", "production_counrty": "UK"}', 'comedy', '7+', 2),
(25, 'Lejonkungen', 88, 'Svenska', 'Svenska', 'https://www.youtube.com/embed/GiXoeAs7S54?si=-DX70YFIr8MFzCHG', 'Lejonungen Simba flyr sitt kungarike efter faderns död, bara för att lära sig meningen med ansvar.', 'lion_king.jpg', '{"actor": "Matthew Broderick, Jeremy Irons", "director": "Roger Allers", "release_year": "1994", "production_company": "Walt Disney Pictures", "production_counrty": "USA"}', 'family', 'btl', 2),
(26, 'Toy Story', 81, 'Svenska', 'Svenska', 'https://www.youtube.com/embed/C7sAUDBxDi8?si=sumsLOlRNrl3-j4V', 'En cowboy-docka känner sig hotad när en ny rymd-actionfigur blir barnkammarens nya favorit.', 'toy_story.jpg', '{"actor": "Tom Hanks, Tim Allen", "director": "John Lasseter", "release_year": "1995", "production_company": "Pixar", "production_counrty": "USA"}', 'family', 'btl', 2),
(27, 'Spirited Away', 125, 'Japanska', 'Svenska', 'https://www.youtube.com/embed/ByXuk9QqQkk?si=vSQNQ6tz0_uPv2Yg', 'En flicka hamnar i en magisk värld styrd av häxor och andar där människor förvandlas till djur.', 'spirited_away.jpg', '{"actor": "Rumi Hiiragi, Miyu Irino", "director": "Hayao Miyazaki", "release_year": "2001", "production_company": "Studio Ghibli", "production_counrty": "Japan"}', 'family', '7+', 2),
(28, 'Ensam Hemma', 103, 'Svenska', 'Svenska', 'https://www.youtube.com/embed/jEDaVHmw7r4?si=_I8H_sTZ7gmHTgzz', 'En åttaåring blir kvarlämnad hemma av misstag och måste försvara huset mot inbrottstjuvar.', 'home_alone.jpg', '{"actor": "Macaulay Culkin, Joe Pesci", "director": "Chris Columbus", "release_year": "1990", "production_company": "Hughes Entertainment", "production_counrty": "USA"}', 'family', 'btl', 2),
(29, 'Elf', 97, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/EkwdYSn3Uws?si=QQV-KIOUbYC-RYba', 'En människa uppfostrad som tomtenisse i Nordpolen reser till New York för att hitta sin riktiga pappa.', 'elf.jpg', '{"actor": "Will Ferrell, James Caan", "director": "Jon Favreau", "release_year": "2003", "production_company": "New Line Cinema", "production_counrty": "USA"}', 'holiday', 'btl', 2),
(30, 'The Nightmare Before Christmas', 76, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/wr6N_hZyBCk?si=h5IDHnbsEI5Nq3wu','Jack Skellington från Halloween Town kidnappar jultomten i ett försök att ta över julen.', 'nightmare_christmas.jpg', '{"actor": "Chris Sarandon, Catherine OHara", "director": "Henry Selick", "release_year": "1993", "production_company": "Touchstone Pictures", "production_counrty": "USA"}', 'holiday', '7+', 2),
(31, 'Love Actually', 135, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/H9Z3_ifFheQ?si=cI1J19fSTesK_NmS', 'Åtta olika par hanterar sina kärleksliv under den hektiska månaden före jul i London.', 'love_actually.jpg', '{"actor": "Hugh Grant, Keira Knightley", "director": "Richard Curtis", "release_year": "2003", "production_company": "Working Title Films", "production_counrty": "UK"}', 'holiday', '11+', 2),
(32, 'The Polar Express', 100, 'Svenska', 'Svenska', 'https://www.youtube.com/embed/f0oyHtZiJJs?si=8Y0kw9HH72mQI-xy', 'En ung pojke kliver ombord på ett magiskt tåg mot Nordpolen för att återfinna sin tro på julen.', 'polar_express.jpg', '{"actor": "Tom Hanks", "director": "Robert Zemeckis", "release_year": "2004", "production_company": "Castle Rock", "production_counrty": "USA"}', 'holiday', 'btl', 2),
