(35, 'The Conjuring', 112, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/ejMMn0t58Lc?si=dCdHbfzL2l8wRS2-', 'Paranormala utredare hjälper en familj som terroriseras av en mörk närvaro i sitt nya hus.', 'conjuring.jpg', '{"actor": "Vera Farmiga, Patrick Wilson", "director": "James Wan", "release_year": "2013", "production_company": "New Line Cinema", "production_counrty": "USA"}', 'horror', '15+', 2),
(36, 'Alien', 117, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/3NHd7oC1w58?si=0wb40WNXYOwBhAWd', 'Besättningen på ett rymdskepp jagas av en aggressiv utomjordisk livsform.', 'alien.jpg', '{"actor": "Sigourney Weaver, Ian Holm", "director": "Ridley Scott", "release_year": "1979", "production_company": "20th Century Fox", "production_counrty": "UK"}', 'horror', '15+', 2),
(37, 'The Notebook', 123, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/NvfI8vUuJ04?si=f8gECTTAwoucx7T8', 'En fattig men passionerad ung man blir kär i en rik kvinna, men de skiljs åt av sina sociala skillnader.', 'notebook.jpg', '{"actor": "Ryan Gosling, Rachel McAdams", "director": "Nick Cassavetes", "release_year": "2004", "production_company": "New Line Cinema", "production_counrty": "USA"}', 'romance', '11+', 2),
(38, 'Titanic', 194, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/dJxj1mou03M?si=GlT3lHgy-wijHlQ5', 'En aristokrat och en fattig konstnär blir kära ombord på den ödesdigra resan med RMS Titanic.', 'titanic.jpg', '{"actor": "Leonardo DiCaprio, Kate Winslet", "director": "James Cameron", "release_year": "1997", "production_company": "Paramount Pictures", "production_counrty": "USA"}', 'romance', '11+', 2),
(39, 'La La Land', 128, 'Engelska', 'Svenska', 'https://www.youtube.com/embed/0pdqf4P9MB8?si=bmUU9iY5sdHFZW9S', 'En jazzpianist och en aspirerande skådespelerska kämpar för att nå sina drömmar i Los Angeles.', 'la_la_land.jpg', '{"actor": "Ryan Gosling, Emma Stone", "director": "Damien Chazelle", "release_year": "2016", "production_company": "Summit Entertainment", "production_counrty": "USA"}', 'romance', 'btl', 2),
